B.a1x=new A.h0("\ud83c\udfaf Lembre-se:","O Quer Valer \xe9 um espa\xe7o para **amigos se desafiarem, rirem e curtirem o futebol** com leveza e respeito. Desafio aceito \xe9 compromisso de resenha, n\xe3o de confus\xe3o.")
B.a1s=new A.h0(null,"\n\u26bd **Respeite o jogo. Respeite o outro. E, acima de tudo, divirta-se.**")
B.Rq=s([B.a1x,B.a1s],t.YV)
B.a1B=new A.qo(B.Rq,null)
B.a1r=new A.h0(null,"\n**1 Respeito acima de tudo.**\nA resenha \xe9 livre, mas o respeito \xe9 obrigat\xf3rio. Zoar faz parte do jogo, ofender n\xe3o. Trate todos os usu\xe1rios com educa\xe7\xe3o e mantenha o esp\xedrito esportivo.")
B.a1o=new A.h0(null,"\n**2 Nada de discurso de \xf3dio ou preconceito.**\nN\xe3o ser\xe3o tolerados coment\xe1rios ofensivos, discriminat\xf3rios ou que incentivem viol\xeancia. Viola\xe7\xf5es resultar\xe3o em banimento imediato.")
B.a1m=new A.h0(null,"\n**3 Proibido conte\xfado expl\xedcito ou violento.**\nImagens, v\xeddeos, memes ou nomes de usu\xe1rios com nudez, viol\xeancia ou material perturbador n\xe3o s\xe3o permitidos.")
B.a1j=new A.h0(null,"\n**4 Sem spam, flood ou autopromo\xe7\xe3o.**\nEvite mensagens repetitivas, propagandas n\xe3o autorizadas ou divulga\xe7\xe3o de links externos que n\xe3o tenham rela\xe7\xe3o com o jogo.")
B.a1w=new A.h0(null,"\n**5 Mantenha o esp\xedrito de divers\xe3o.**\nQuer Valer \xe9 sobre rivalidade saud\xe1vel e bom humor. Discuss\xf5es exageradas, provoca\xe7\xf5es agressivas ou brigas fora de tom n\xe3o t\xeam espa\xe7o aqui.")
B.a1v=new A.h0(null,"\n**6 Nada de links suspeitos ou pirataria.**\n\xc9 proibido compartilhar links de apostas, streams ilegais ou qualquer conte\xfado n\xe3o oficial.")
B.a1n=new A.h0(null,"\n**7 Seja voc\xea mesmo.**\nN\xe3o se passe por outras pessoas, jogadores, administradores ou marcas. Impersonar algu\xe9m resultar\xe1 em puni\xe7\xe3o.")
B.a1p=new A.h0(null,"\n**8 Privacidade \xe9 coisa s\xe9ria.**\nN\xe3o compartilhe informa\xe7\xf5es pessoais suas nem de terceiros. Nenhum membro da equipe Quer Valer pedir\xe1 dados pessoais em mensagens privadas.")
B.a1u=new A.h0(null,"\n**9 Canal certo para cada conversa.**\nSe estiver interagindo em grupos ou comunidades, use os espa\xe7os adequados para cada tipo de assunto (desafios, resultados, memes, etc.).")
B.a1t=new A.h0(null,"\n**10 Jogue limpo \u2014 literalmente.**\nTentativas de manipular resultados, burlar desafios ou criar m\xfaltiplas contas para obter vantagem resultar\xe3o em banimento.")
B.a1k=new A.h0(null,"\n**11 Idade m\xednima: 18 anos.**\nO Quer Valer \xe9 uma plataforma voltada a adultos. Ao participar, voc\xea confirma que tem 18 anos ou mais e concorda com nossos Termos de Uso.")
